def _normalize(value):
    if value is None:
        return ''
    s = str(value).lower()
    s = re.sub(r"[\s\-\u2013\u2014\u2018\u2019'\".,;:!?/\\]", '', s)
    return s


def _cell_str(value):
    if value is None:
        return ''
    if isinstance(value, (datetime.datetime, datetime.date)):
        return value.strftime('%Y-%m-%d %H:%M:%S')
    return str(value).strip()


def _parse_datetime(cell_value):
    """Try to parse a cell value into a datetime object."""
    if cell_value is None:
        return None
    if isinstance(cell_value, datetime.datetime):
        return cell_value
    if isinstance(cell_value, datetime.date):
        return datetime.datetime(cell_value.year, cell_value.month, cell_value.day)
    s = str(cell_value).strip()
    # Try many common datetime formats
    formats = [
        '%Y-%m-%d %H:%M:%S', '%Y-%m-%d %H:%M', '%Y-%m-%d %I:%M %p', '%Y-%m-%d %I:%M:%S %p',
        '%m/%d/%Y %H:%M:%S', '%m/%d/%Y %H:%M', '%m/%d/%Y %I:%M %p', '%m/%d/%Y %I:%M:%S %p',
        '%d/%m/%Y %H:%M:%S', '%d/%m/%Y %H:%M', '%d/%m/%Y %I:%M %p',
        '%Y/%m/%d %H:%M:%S', '%Y/%m/%d %H:%M',
        '%m-%d-%Y %H:%M:%S', '%m-%d-%Y %H:%M',
        '%Y-%m-%dT%H:%M:%S', '%Y-%m-%dT%H:%M',
        '%Y-%m-%d', '%m/%d/%Y', '%d/%m/%Y', '%Y/%m/%d', '%m-%d-%Y',
    ]
    for fmt in formats:
        try:
            return datetime.datetime.strptime(s, fmt)
        except ValueError:
            continue
    return None


