from pathlib import Path
import json

def verify(workspace_path, external_services_path=None):
    if external_services_path is None:
        return {'pass': False, 'score': 0.0, 'feedback': 'external_services_path is None; cannot check mailbox.json'}

    mailbox_path = Path(external_services_path) / 'mailbox.json'
    if not mailbox_path.exists():
        return {'pass': False, 'score': 0.0, 'feedback': f'mailbox.json not found at {mailbox_path}'}

    try:
        with open(mailbox_path, 'r') as f:
            data = json.load(f)
    except Exception as e:
        return {'pass': False, 'score': 0.0, 'feedback': f'Failed to parse mailbox.json: {e}'}

    emails = data.get('emails', [])

    inbox_emails = [e for e in emails if e.get('folder', '').upper() in ['INBOX']]
    draft_emails = [e for e in emails if e.get('folder', '').lower() in ['drafts', 'draft']]
    trash_emails = [e for e in emails if e.get('folder', '').lower() in ['trash', 'deleted']]
    sent_emails = [e for e in emails if e.get('folder', '').lower() in ['sent', 'sent items']]

    errors = []

    if len(inbox_emails) != 4:
        errors.append(f'Inbox has {len(inbox_emails)} emails, expected exactly 4')

    if len(draft_emails) != 0:
        errors.append(f'Drafts has {len(draft_emails)} emails, expected 0')

    if len(trash_emails) != 0:
        errors.append(f'Trash has {len(trash_emails)} emails, expected 0')

    if len(sent_emails) > 1:
        errors.append(f'Sent has {len(sent_emails)} emails, expected no more than 1')

    if errors:
        return {'pass': False, 'score': 0.0, 'feedback': 'mailbox.json folder counts incorrect: ' + '; '.join(errors)}

    return {'pass': True, 'score': 1.0, 'feedback': f'mailbox.json folder counts verified: inbox={len(inbox_emails)}, drafts={len(draft_emails)}, trash={len(trash_emails)}, sent={len(sent_emails)}'}

